// // This module implements a Down/Up counter with a 4-bit output and a control input to specify counting direction (down or up). The counter decrements when the up control input is high and increments when it is low. The counter should also have a reset input that sets the counter to zero.
module up_down_counter (  
    input wire clk,  
    input wire reset,  
    input wire up,  
    output reg [3:0] count  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            count <= 4'b0000;  
        end else if (up) begin  
            count <= count + 1;  
        end else begin  
            count <= count - 1;  
        end  
    end  
endmodule
